/**
 * RLS / Auth SQL draft generator (Phase 3-M).
 * Generates SQL files only — no Supabase connection.
 */

import fs from "node:fs";
import path from "node:path";

export const ADMIN_AUTH_APPROACH = "admin_users table + is_admin()";

/** @typedef {{ ok: boolean, matches: string[] }} DangerousSqlScan */

export const RLS_DRAFT_SQL = `-- RLS / Auth draft (Phase 3-M)
-- Generated by static-to-astro — DO NOT apply to production without review.
-- Apply manually in staging Supabase SQL Editor only.
-- Safety: idempotent policy draft only (no destructive DDL/DML statements).

-- ---------------------------------------------------------------------------
-- Overview
-- ---------------------------------------------------------------------------
-- Public read:  published = true (anon + authenticated)
-- Admin write:  is_admin() via admin_users table (authenticated)
-- Service role: bypasses RLS — CLI / server-side only, NEVER expose to browser
--
-- Recommended admin model: admin_users table (see docs/phase3-m-auth-rls.md)
-- Final decision: TBD — confirm with project owner before production apply.

-- ---------------------------------------------------------------------------
-- 1. admin_users table
-- ---------------------------------------------------------------------------
create table if not exists public.admin_users (
  user_id uuid primary key references auth.users (id) on delete cascade,
  email text,
  role text not null default 'admin',
  created_at timestamptz not null default now()
);

comment on table public.admin_users is
  'CMS administrators. Bootstrap first row via service role in SQL Editor.';

-- ---------------------------------------------------------------------------
-- 2. is_admin() helper
-- ---------------------------------------------------------------------------
-- SECURITY DEFINER runs as function owner — keep body minimal, fixed search_path.
-- Risk: misconfigured owner/grants could widen access; review before production.
-- Service role key bypasses RLS entirely (separate from this function).
create or replace function public.is_admin()
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select exists (
    select 1
    from public.admin_users au
    where au.user_id = auth.uid()
      and au.role = 'admin'
  );
$$;

comment on function public.is_admin() is
  'True when auth.uid() is listed in admin_users with role=admin.';

revoke all on function public.is_admin() from public;
grant execute on function public.is_admin() to authenticated;

-- ---------------------------------------------------------------------------
-- 3. Enable RLS
-- ---------------------------------------------------------------------------
alter table public.schedule_months enable row level security;
alter table public.schedules enable row level security;
alter table public.discography enable row level security;
alter table public.discography_tracks enable row level security;
alter table public.admin_users enable row level security;

-- ---------------------------------------------------------------------------
-- 4. Public read policies (published rows only)
-- ---------------------------------------------------------------------------

-- schedule_months
drop policy if exists "schedule_months_public_select" on public.schedule_months;
create policy "schedule_months_public_select"
  on public.schedule_months
  for select
  to anon, authenticated
  using (published = true);

-- schedules
drop policy if exists "schedules_public_select" on public.schedules;
create policy "schedules_public_select"
  on public.schedules
  for select
  to anon, authenticated
  using (published = true);

-- discography
drop policy if exists "discography_public_select" on public.discography;
create policy "discography_public_select"
  on public.discography
  for select
  to anon, authenticated
  using (published = true);

-- discography_tracks (parent discography must be published)
drop policy if exists "discography_tracks_public_select" on public.discography_tracks;
create policy "discography_tracks_public_select"
  on public.discography_tracks
  for select
  to anon, authenticated
  using (
    exists (
      select 1
      from public.discography d
      where d.legacy_id = discography_tracks.discography_legacy_id
        and d.published = true
    )
  );

-- ---------------------------------------------------------------------------
-- 5. Admin policies (full CRUD on CMS tables)
-- ---------------------------------------------------------------------------

-- schedule_months
drop policy if exists "schedule_months_admin_all" on public.schedule_months;
create policy "schedule_months_admin_all"
  on public.schedule_months
  for all
  to authenticated
  using (public.is_admin())
  with check (public.is_admin());

-- schedules
drop policy if exists "schedules_admin_all" on public.schedules;
create policy "schedules_admin_all"
  on public.schedules
  for all
  to authenticated
  using (public.is_admin())
  with check (public.is_admin());

-- discography
drop policy if exists "discography_admin_all" on public.discography;
create policy "discography_admin_all"
  on public.discography
  for all
  to authenticated
  using (public.is_admin())
  with check (public.is_admin());

-- discography_tracks
drop policy if exists "discography_tracks_admin_all" on public.discography_tracks;
create policy "discography_tracks_admin_all"
  on public.discography_tracks
  for all
  to authenticated
  using (public.is_admin())
  with check (public.is_admin());

-- ---------------------------------------------------------------------------
-- 6. admin_users policies
-- ---------------------------------------------------------------------------
-- Bootstrap: insert first admin via SQL Editor (service role bypasses RLS), e.g.:
--   insert into public.admin_users (user_id, email, role)
--   values ('<auth.users.id>', 'admin@example.com', 'admin');

drop policy if exists "admin_users_admin_select" on public.admin_users;
create policy "admin_users_admin_select"
  on public.admin_users
  for select
  to authenticated
  using (public.is_admin());

drop policy if exists "admin_users_admin_insert" on public.admin_users;
create policy "admin_users_admin_insert"
  on public.admin_users
  for insert
  to authenticated
  with check (public.is_admin());

drop policy if exists "admin_users_admin_update" on public.admin_users;
create policy "admin_users_admin_update"
  on public.admin_users
  for update
  to authenticated
  using (public.is_admin())
  with check (public.is_admin());

drop policy if exists "admin_users_admin_delete" on public.admin_users;
create policy "admin_users_admin_delete"
  on public.admin_users
  for delete
  to authenticated
  using (public.is_admin());

-- ---------------------------------------------------------------------------
-- End of RLS draft (Phase 3-M)
-- Admin UI save / Auth login validation: Phase 3-N+
-- ---------------------------------------------------------------------------
`;

export const RLS_VERIFY_SQL = `-- RLS verification queries (Phase 3-M)
-- Run in staging Supabase SQL Editor AFTER applying rls-draft.sql.
-- Service role session sees all rows; use anon/authenticated clients to test public read.

-- ---------------------------------------------------------------------------
-- RLS enabled?
-- ---------------------------------------------------------------------------
select schemaname, tablename, rowsecurity
from pg_tables
where schemaname = 'public'
  and tablename in (
    'schedule_months',
    'schedules',
    'discography',
    'discography_tracks',
    'admin_users'
  )
order by tablename;

-- ---------------------------------------------------------------------------
-- Policy list
-- ---------------------------------------------------------------------------
select schemaname, tablename, policyname, permissive, roles, cmd
from pg_policies
where schemaname = 'public'
  and tablename in (
    'schedule_months',
    'schedules',
    'discography',
    'discography_tracks',
    'admin_users'
  )
order by tablename, policyname;

-- ---------------------------------------------------------------------------
-- Row counts (service role / SQL Editor — not RLS-filtered)
-- ---------------------------------------------------------------------------
select 'schedule_months' as table_name, count(*) from public.schedule_months
union all
select 'schedules', count(*) from public.schedules
union all
select 'discography', count(*) from public.discography
union all
select 'discography_tracks', count(*) from public.discography_tracks
union all
select 'admin_users', count(*) from public.admin_users;

-- ---------------------------------------------------------------------------
-- Published vs total (sanity check before/after RLS)
-- ---------------------------------------------------------------------------
select 'schedules_published' as metric, count(*) from public.schedules where published = true
union all
select 'schedules_total', count(*) from public.schedules
union all
select 'discography_published', count(*) from public.discography where published = true
union all
select 'discography_total', count(*) from public.discography;

-- ---------------------------------------------------------------------------
-- Orphan tracks (should remain 0)
-- ---------------------------------------------------------------------------
select t.discography_legacy_id, t.track_number, t.title
from public.discography_tracks t
left join public.discography d on t.discography_legacy_id = d.legacy_id
where d.legacy_id is null;

-- ---------------------------------------------------------------------------
-- is_admin() smoke test (run as authenticated admin user in SQL Editor if supported)
-- ---------------------------------------------------------------------------
-- select public.is_admin();

-- ---------------------------------------------------------------------------
-- Anon read simulation (Phase 3-N — not automated here)
-- ---------------------------------------------------------------------------
-- From app code, create Supabase client with anon key only:
--   const { data } = await supabase.from('schedules').select('*');
-- Expect: only rows where published = true.
-- Unpublished rows must NOT appear for anon/authenticated non-admin users.
--
-- Admin authenticated client (user in admin_users):
--   Expect: all rows visible; insert/update/delete allowed on CMS tables.
--
-- Service role (CLI / server-side only):
--   Bypasses RLS — do NOT use in browser or Astro client bundles.
`;

const DANGEROUS_PATTERNS = [
  { name: "drop table", regex: /\bdrop\s+table\b/i },
  { name: "drop schema", regex: /\bdrop\s+schema\b/i },
  { name: "truncate", regex: /\btruncate\b/i },
  { name: "delete from", regex: /\bdelete\s+from\b/i },
];

/**
 * Strip SQL line/block comments before scanning for destructive statements.
 * @param {string} sql
 */
function stripSqlComments(sql) {
  return sql
    .replace(/\/\*[\s\S]*?\*\//g, "")
    .replace(/^\s*--.*$/gm, "");
}

/**
 * @param {string} sql
 * @returns {DangerousSqlScan}
 */
export function scanDangerousSql(sql) {
  const stripped = stripSqlComments(sql);
  const matches = [];
  for (const { name, regex } of DANGEROUS_PATTERNS) {
    if (regex.test(stripped)) {
      matches.push(name);
    }
  }
  return { ok: matches.length === 0, matches };
}

/**
 * @param {{ outDir: string, dangerousScan: DangerousSqlScan }} opts
 */
export function formatRlsImplementationReport({ outDir, dangerousScan }) {
  const outAbs = path.resolve(outDir);
  return [
    "# RLS_IMPLEMENTATION_REPORT",
    "",
    `Generated at: ${new Date().toISOString()}`,
    "Mode: **SQL draft generation only** (no Supabase connection)",
    "",
    "## Purpose (Phase 3-M)",
    "",
    "Prepare Auth / RLS policies for staging CMS tables before enabling Admin save.",
    "",
    "## Recommended admin model",
    "",
    `- **Approach:** ${ADMIN_AUTH_APPROACH}`,
    "- **Final decision:** TBD — confirm with project owner before production apply",
    "",
    "See `tools/static-to-astro/docs/phase3-m-auth-rls.md` for comparison with JWT `app_metadata.role`.",
    "",
    "## Output files",
    "",
    `- \`${path.join(outAbs, "rls-draft.sql")}\``,
    `- \`${path.join(outAbs, "rls-verify.sql")}\``,
    "",
    "## Policy summary",
    "",
    "| Table | Public read | Admin |",
    "| --- | --- | --- |",
    "| schedule_months | `published = true` | ALL (via `is_admin()`) |",
    "| schedules | `published = true` | ALL |",
    "| discography | `published = true` | ALL |",
    "| discography_tracks | parent `discography.published = true` | ALL |",
    "| admin_users | — | SELECT/INSERT/UPDATE/DELETE for admins only |",
    "",
    "## Security notes",
    "",
    "- `is_admin()` is **SECURITY DEFINER** with fixed `search_path = public`",
    "- **Service role key bypasses RLS** — CLI / server-side only, never in browser",
    "- Phase 3-M does **not** enable Admin UI save or create Auth users",
    "",
    "## Dangerous SQL scan (rls-draft.sql)",
    "",
    dangerousScan.ok
      ? "No `DROP TABLE`, `DROP SCHEMA`, `TRUNCATE`, or `DELETE FROM` detected."
      : `**FAILED:** detected: ${dangerousScan.matches.join(", ")}`,
    "",
    "## Staging apply (manual — not done by this CLI)",
    "",
    "1. Review `rls-draft.sql` and `docs/phase3-m-auth-rls.md`",
    "2. Apply `schema-draft.sql` is already done (Phase 3-J)",
    "3. Run `rls-draft.sql` in **staging** SQL Editor",
    "4. Bootstrap first admin via service role:",
    "   `insert into admin_users (user_id, email, role) values (...);`",
    "5. Run `rls-verify.sql`",
    "6. Test anon read with published-only rows (Phase 3-N)",
    "",
    "## Rollback (staging only — manual)",
    "",
    "Drop policies, disable RLS, drop `admin_users`, drop `is_admin()` — see docs/phase3-m-auth-rls.md.",
    "Do not run against production without review.",
    "",
    "## Not in scope (Phase 3-M)",
    "",
    "- Applying SQL to Supabase",
    "- Auth user creation / admin_users seed",
    "- Admin UI save enablement",
    "- Root `supabase/migrations/`",
    "",
    "## Next phases",
    "",
    "- **Phase 3-N:** Apply RLS on staging + anon/admin read verification",
    "- **Phase 3-O:** Admin save via authenticated server routes",
    "- **Phase 3-P:** Production RLS review + deploy",
    "",
  ].join("\n");
}

/**
 * @param {string} astroDir
 * @param {{ outRel: string, approach: string, dangerousOk: boolean }} summary
 */
export function appendPhase3MToConversionReport(astroDir, summary) {
  const reportPath = path.join(path.resolve(astroDir), "CONVERSION_REPORT.md");
  if (!fs.existsSync(reportPath)) return;

  const block = [
    "",
    "## Auth / RLS draft (Phase 3-M)",
    "",
    `- **Output:** \`${summary.outRel}\``,
    `- **Admin model (recommended):** ${summary.approach}`,
    `- **Dangerous SQL scan:** ${summary.dangerousOk ? "pass" : "FAIL"}`,
    `- **Applied to Supabase:** no (draft only)`,
    `- **Admin save:** still disabled`,
    "",
  ].join("\n");

  let content = fs.readFileSync(reportPath, "utf8");
  const marker = "## Auth / RLS draft (Phase 3-M)";
  if (content.includes(marker)) {
    content = `${content.split(marker)[0].trimEnd()}${block}`;
  } else {
    content = `${content.trimEnd()}${block}`;
  }
  fs.writeFileSync(reportPath, content, "utf8");
}

/**
 * @param {{ outDir: string, astroDir?: string }} opts
 */
export function runRlsDraftPipeline({ outDir, astroDir }) {
  const outAbs = path.resolve(outDir);
  fs.mkdirSync(outAbs, { recursive: true });

  const draftPath = path.join(outAbs, "rls-draft.sql");
  const verifyPath = path.join(outAbs, "rls-verify.sql");
  const reportPath = path.join(outAbs, "RLS_IMPLEMENTATION_REPORT.md");

  fs.writeFileSync(draftPath, RLS_DRAFT_SQL, "utf8");
  fs.writeFileSync(verifyPath, RLS_VERIFY_SQL, "utf8");

  const dangerousScan = scanDangerousSql(RLS_DRAFT_SQL);
  const report = formatRlsImplementationReport({ outDir: outAbs, dangerousScan });
  fs.writeFileSync(reportPath, report, "utf8");

  if (astroDir) {
    appendPhase3MToConversionReport(astroDir, {
      outRel: path.relative(path.resolve(astroDir), outAbs),
      approach: ADMIN_AUTH_APPROACH,
      dangerousOk: dangerousScan.ok,
    });
  }

  return {
    outDir: outAbs,
    draftPath,
    verifyPath,
    reportPath,
    dangerousScan,
  };
}
